var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"후우…… 최고 관리자 회의를 앞두고 뒤숭숭한 마당에 기어코 일을 벌였군.","JPN":"ふう……最高管理者会議の前で浮足立っているときに、やらかしてくれたな。","ENG":"*Sigh...* You just had to cause trouble right before the Supreme Administrator meeting.","TWN":"哀……最高管理者會議召開前夕亂哄哄的，硬要挑這個時候惹事嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"이번 일은 조용히 넘어갈 수 없어. 한동안 정보부가 시끄러울 거야.","JPN":"今度のことは伏せられないだろう。しばらくは情報部がうるさくなる。","ENG":"This one won't slide under the radar. The Intelligence Agency is going to be all over it.","TWN":"這次的事沒辦法就這樣含糊帶過，情報部這一陣子應該會很熱鬧。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아이들은 확실히 단속하게. 비슷한 일이 다시 벌어지면 그 때는 나도 뒤를 봐 줄 수 없어.","JPN":"子どもたちはしっかり管理してくれよ。また似たようなことが発生すると、その時には私もフォローできない。","ENG":"Don't let those kids out of your sight. If something like this happens again, I won't be able to cover for you.","TWN":"把那些孩子管好，下次要是再發生類似的事，到時候恐怕我也無能為力。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어휴, 저 양반은 또 오므라이스 먹고 있네. 세 끼 전부 오므라이스로 떼우겠어, 아주.","JPN":"もう、あの人はまたオムライス食べてる。三食全部オムライスになるかもしれないわ、まったく。","ENG":"Ugh... Is he eating that kids' meal again? Is fried rice omelet all he ever eats?","TWN":"真是的，那位先生又在吃蛋包飯，看來三餐都要吃蛋包飯囉。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아무튼 그렇게 됐어. 도로시 네 다리는 좀 나중에 수리해야겠다.","JPN":"とにかく、そういうことで。ドロシー、あんたの足は後で修理することになるわね。","ENG":"Anyway, it is what it is. Guess we'll have to get your legs repaired another day.","TWN":"總之就是這樣，桃樂絲你的腿可能要之後才能修理。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"헴스워스 할아버지를 부르면 안 돼?","JPN":"ヘムズワースお爺さんを呼んじゃダメなの？","ENG":"Can't we just call Helmsworth?","TWN":"不能找漢姆沃斯爺爺嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"그 할아버지가 부른다고 와 줄까.","JPN":"呼んだところで、あのお爺さんが来てくれるかな。","ENG":"Do you think he'll come just because you called?","TWN":"要找那個爺爺來嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"안 돼. 토토를 해체하려고 할지도 몰라.","JPN":"ダメ。トトを解体しようとするかもしれないよ。","ENG":"No. He might try to dissect Toto.","TWN":"不要，他可能會想把托托解體。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐, 조금 늦어져도 괜찮아. 당분간 달릴 일은 없을 것 같거든.","JPN":"ま、少し遅くなっても大丈夫。しばらく走ることはなさそうだからね。","ENG":"Eh, I don't mind if it's a little later. I don't think I'll have to run for a while anyway.","TWN":"沒關係啦，晚點修也可以，暫時也沒什麼需要奔跑的事吧。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흥. 그러시겠지. 위원회 코털을 건드리는 대형 사고까지 쳤는걸.","JPN":"ふん。そうでしょうとも。委員会の機嫌を損ねる大事故までやらかしたんだから。","ENG":"Hmph. You said it. Causing a major incident that even the committee is interested in.","TWN":"哼，是吧，這可是觸碰到委員會敏感神經的大型事故。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"리코리스도 같이 건드렸어.","JPN":"リコリスも一緒にやらかした。","ENG":"You're part of it too, Lycoris.","TWN":"莉克麗絲也有一起觸碰。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"맞아. 우린 공범이야.","JPN":"そうだよ。私たちは共犯なの。","ENG":"Yeah, you're our accomplice.","TWN":"對啊，我們是共犯。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"난 이미 한 건 걸려 있단 말이야! 블랙 네트워크에서 수배서 보고 얼마나 기겁했는데!","JPN":"私はすでに一件あるのよ！　ブラックネットワークで手配書見てどれだけビックリしたと思ってるの！？","ENG":"Well, this is my strike two, okay?! Do you know how horrified I was to see my bounties posted on the Dark Network?!","TWN":"我早就被記一筆啦！在黑色網路看到通緝令時我有多震驚！"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아아…… 내가 못 살아, 진짜.","JPN":"ああ……イヤだわ、もう。","ENG":"Ugh... You're going to drive me crazy.","TWN":"吼……我真的會氣死。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런데 우리는 이제 어떻게 되는 거야? 관리국의 현장 요원으로 구른다거나?","JPN":"ところで、私たちはこれからどうなるの？　管理局の現場要員として使われるとか？","ENG":"So, what happens to us now? Are we now field agents of the Administration?","TWN":"那我們現在該怎麼辦？去當管理局的幹員嗎？"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"가출 청소년에게 손 벌릴 만큼 관리국이 만만하진 않거든? 나 같은 말단이랑 좀 어울렸다고 콧대만 높아져선.","JPN":"家出した青少年を雇ってくれるほど管理局は甘くないのよ。私みたいな末端と付き合ったからって偉ぶっちゃって。","ENG":"What, you think you're a big deal now because you hang out with a low-level agent like me? Or did you really believe the Administration would hire some runaway kids as field agents?","TWN":"管理局可沒有好欺負到會向離家出走的青少年伸出手，他們都是用鼻孔在看我們這種基層人員的。"},"stage":{"bg":"HELI_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};